
  const nav=document.getElementById('nav');
  const onScroll=()=>nav.classList.toggle('scrolled',window.scrollY>40);
  onScroll();window.addEventListener('scroll',onScroll,{passive:true});
  const burger=document.getElementById('burger');
  if(burger)burger.addEventListener('click',()=>document.getElementById('contacto').scrollIntoView({behavior:'smooth'}));

  const io=new IntersectionObserver((es)=>{es.forEach(e=>{if(e.isIntersecting){e.target.classList.add('in');io.unobserve(e.target);}});},{threshold:.12,rootMargin:'0px 0px -7% 0px'});
  document.querySelectorAll('.reveal').forEach((el,i)=>{el.style.transitionDelay=(i%3*70)+'ms';io.observe(el);});

  const IMG={logo:'assets/img/logo.webp',bottle:'assets/img/bottle.webp'};
  document.querySelectorAll('[data-img]').forEach(el=>{el.src=IMG[el.dataset.img];});

  const WA='573001234567';
  const waLink=(t)=>'https://wa.me/'+WA+'?text='+encodeURIComponent(t);
  const general='Hola, quiero información de los perfumes y la medicina natural de DOS CASAS.';
  var wf=document.getElementById('waFloat'); if(wf) wf.href=waLink(general);
  document.querySelectorAll('[data-wa-general]').forEach(a=>a.href=waLink(general));
  function pedir(name,msg){var a=document.createElement('a');a.className='pedir-btn';a.target='_blank';a.rel='noopener';a.href=waLink(msg);a.innerHTML='Pedir por WhatsApp <span>→</span>';return a;}
