  /* ===== Generador de ritual ===== */
  (function(){
    var box=document.getElementById('ritual-gen'); if(!box) return;
    var RIT={
      melena:{n:'Melena de León',fmt:'30 cápsulas',p:95000,f:[
        'hoy quiero que mi mente trabaje a mi favor: arranco mi ritual de foco con Melena de León',
        'busco claridad sin el bajón de la cafeína, me llevo Melena de León para concentrarme',
        'quiero pensar mejor y rendir más durante el día, mi ritual de enfoque es Melena de León',
        'necesito la mente afilada para lo que viene, empiezo con Melena de León',
        'menos ruido y más foco: hoy mi ritual es Melena de León'
      ]},
      cordyceps:{n:'Cordyceps',fmt:'30 cápsulas',p:110000,f:[
        'le quiero subir el volumen al día, empiezo mi ritual de energía con Cordyceps',
        'busco vitalidad de la buena para moverme sin parar, me llevo Cordyceps',
        'quiero rendir físicamente y sin químicos, mi ritual de energía es Cordyceps',
        'energía que no me cobre después: hoy elijo Cordyceps',
        'voy a encender el cuerpo para todo el día, mi ritual es Cordyceps'
      ]},
      coladepavo:{n:'Cola de Pavo',fmt:'30 cápsulas',p:98000,f:[
        'quiero cuidarme desde adentro, mi escudo diario es Cola de Pavo',
        'busco defensa natural todo el año, me llevo Cola de Pavo',
        'quiero una inmunidad que trabaje en silencio, mi ritual es Cola de Pavo',
        'me protejo de raíz con betaglucanos: hoy es Cola de Pavo',
        'mi escudo de cada día se llama Cola de Pavo'
      ]},
      reishi:{n:'Reishi',fmt:'30 cápsulas',p:105000,f:[
        'quiero apagar el ruido y respirar, mi calma de hoy es Reishi',
        'busco un descanso que se sienta, cierro el día con Reishi',
        'menos estrés y mejor sueño: mi ritual de calma es Reishi',
        'la calma también es un ritual, hoy elijo Reishi',
        'quiero soltar el día y dormir como se debe, me llevo Reishi'
      ]}
    };
    var nameEl=document.getElementById('rgName'),
        out=document.getElementById('rgOut'), phraseEl=document.getElementById('rgPhrase'),
        sendEl=document.getElementById('rgSend'), againEl=document.getElementById('rgAgain'),
        hintEl=document.getElementById('rgHint');
    var cur=null, lastIdx=-1;
    function pick(arr){ var i; do{ i=Math.floor(Math.random()*arr.length); }while(arr.length>1 && i===lastIdx); lastIdx=i; return i; }
    function cap(s){ return s ? s.charAt(0).toUpperCase()+s.slice(1) : s; }
    function capWords(s){ return s.replace(/\S+/g,function(w){return w.charAt(0).toUpperCase()+w.slice(1).toLowerCase();}); }
    function waNum(){ return (typeof WA!=='undefined' && WA) ? WA : '573001234567'; }
    function build(){
      if(!cur) return;
      var d=RIT[cur], frase=d.f[pick(d.f)];
      var raw=(nameEl && nameEl.value || '').trim().replace(/\s+/g,' ').slice(0,24);
      var nm=raw ? capWords(raw) : '';
      var shown = nm ? (nm+', '+frase+'.') : (cap(frase)+'.');
      phraseEl.textContent = '“'+shown+'”';
      var saludo = nm ? ('Hola 🌿 Soy '+nm+'. ') : 'Hola 🌿 ';
      var msg = saludo + cap(frase) + ' — '+d.fmt+', $'+d.p.toLocaleString('es-CO')+'. ¿Está disponible?';
      sendEl.href = 'https://wa.me/'+waNum()+'?text='+encodeURIComponent(msg);
      out.hidden=false; if(hintEl) hintEl.hidden=true;
    }
    box.querySelectorAll('.rg-chip').forEach(function(c){
      c.addEventListener('click', function(){
        box.querySelectorAll('.rg-chip').forEach(function(x){x.classList.remove('active');});
        c.classList.add('active'); cur=c.dataset.key; lastIdx=-1; build();
      });
    });
    if(againEl) againEl.addEventListener('click', build);
    if(nameEl) nameEl.addEventListener('input', function(){ if(cur) build(); });
  })();

